import { useEffect } from "react";
import { useLocation } from "react-router-dom";
import {
  DEFAULT_OG_IMAGE,
  DEFAULT_OG_IMAGE_HEIGHT,
  DEFAULT_OG_IMAGE_WIDTH,
  ORGANIZATION_SCHEMA,
  buildAbsoluteUrl,
  buildWebsiteSchema,
  getSeoForPath,
} from "./seoConfig.js";

const ensureMeta = (id, attribute, key, content) => {
  let element = document.getElementById(id);
  if (!element) {
    element = document.createElement("meta");
    element.id = id;
    document.head.appendChild(element);
  }

  element.setAttribute(attribute, key);
  element.setAttribute("content", content);
};

const removeElementById = (id) => {
  const element = document.getElementById(id);
  if (element && element.parentNode) {
    element.parentNode.removeChild(element);
  }
};

const ensureLink = (id, rel, href, extra = {}) => {
  let element = document.getElementById(id);
  if (!element) {
    element = document.createElement("link");
    element.id = id;
    document.head.appendChild(element);
  }

  element.setAttribute("rel", rel);
  element.setAttribute("href", href);
  Object.entries(extra).forEach(([name, value]) => {
    element.setAttribute(name, value);
  });
};

const ensureJsonLd = (id, payload) => {
  let element = document.getElementById(id);
  if (!element) {
    element = document.createElement("script");
    element.id = id;
    element.type = "application/ld+json";
    document.head.appendChild(element);
  }

  element.textContent = JSON.stringify(payload);
};

const SeoManager = () => {
  const { pathname } = useLocation();

  useEffect(() => {
    const seo = getSeoForPath(pathname);
    const canonicalUrl = buildAbsoluteUrl(seo.canonicalPath || pathname);
    const ogTitle = seo.ogTitle || seo.title;
    const ogDescription = seo.ogDescription || seo.description;
    const ogImage = seo.ogImage || DEFAULT_OG_IMAGE;
    const fbAppId = (import.meta.env.VITE_FB_APP_ID || "").trim();

    document.title = seo.title;

    ensureMeta("seo-description", "name", "description", seo.description);
    ensureMeta("seo-robots", "name", "robots", seo.robots || "index,follow");

    ensureMeta("seo-og-type", "property", "og:type", "website");
    ensureMeta("seo-og-url", "property", "og:url", canonicalUrl);
    ensureMeta("seo-og-title", "property", "og:title", ogTitle);
    ensureMeta("seo-og-description", "property", "og:description", ogDescription);
    ensureMeta("seo-og-image", "property", "og:image", ogImage);
    ensureMeta("seo-og-image-width", "property", "og:image:width", String(DEFAULT_OG_IMAGE_WIDTH));
    ensureMeta("seo-og-image-height", "property", "og:image:height", String(DEFAULT_OG_IMAGE_HEIGHT));
    ensureMeta("seo-og-site-name", "property", "og:site_name", "Iskryb");
    if (fbAppId) {
      ensureMeta("seo-fb-app-id", "property", "fb:app_id", fbAppId);
    } else {
      removeElementById("seo-fb-app-id");
    }

    ensureMeta("seo-twitter-card", "name", "twitter:card", "summary_large_image");
    ensureMeta("seo-twitter-title", "name", "twitter:title", ogTitle);
    ensureMeta("seo-twitter-description", "name", "twitter:description", ogDescription);
    ensureMeta("seo-twitter-image", "name", "twitter:image", ogImage);
    ensureMeta("seo-twitter-image-width", "name", "twitter:image:width", String(DEFAULT_OG_IMAGE_WIDTH));
    ensureMeta("seo-twitter-image-height", "name", "twitter:image:height", String(DEFAULT_OG_IMAGE_HEIGHT));

    ensureLink("seo-canonical", "canonical", canonicalUrl);
    ensureLink("seo-hreflang-en", "alternate", canonicalUrl, { hreflang: "en-US" });
    ensureLink("seo-hreflang-default", "alternate", canonicalUrl, {
      hreflang: "x-default",
    });

    ensureJsonLd("seo-ld-website", buildWebsiteSchema(canonicalUrl));
    ensureJsonLd("seo-ld-organization", ORGANIZATION_SCHEMA);
  }, [pathname]);

  return null;
};

export default SeoManager;

export const SITE_NAME = "Iskryb";
export const SITE_URL = "https://iskrib.com";
export const DEFAULT_OG_IMAGE = `${SITE_URL}/assets/no-image.png`;
export const DEFAULT_OG_IMAGE_WIDTH = 1200;
export const DEFAULT_OG_IMAGE_HEIGHT = 630;

export const DEFAULT_SEO = {
  title: `${SITE_NAME} | Social Journaling and Opinions`,
  description:
    "Iskryb is a social journaling platform where you can publish journals, share opinions, and organize collections.",
  canonicalPath: "/",
  robots: "index,follow",
};

export const SEO_ROUTES = [
  {
    path: "/",
    title: `${SITE_NAME} | Social Journaling and Opinions`,
    description:
      "Publish journals, share opinions, and build collections in one social writing platform.",
    canonicalPath: "/",
    robots: "index,follow",
    prerender: true,
    sitemap: { changefreq: "daily", priority: "1.0" },
  },
  {
    path: "/home",
    title: `${SITE_NAME} Home Feed`,
    description:
      "Explore journals and ideas from the Iskryb community in the home feed.",
    canonicalPath: "/home",
    robots: "index,follow",
    prerender: true,
    sitemap: { changefreq: "daily", priority: "0.9" },
  },
  {
    path: "/home/opinions",
    title: `${SITE_NAME} Opinions`,
    description:
      "Read and respond to community opinions on Iskryb with threaded discussions.",
    canonicalPath: "/home/opinions",
    robots: "index,follow",
    prerender: true,
    sitemap: { changefreq: "daily", priority: "0.8" },
  },
  {
    path: "/home/explore",
    title: `${SITE_NAME} Explore`,
    description:
      "Discover the hottest posts and search across community journals on Iskryb.",
    canonicalPath: "/home/explore",
    robots: "index,follow",
    prerender: true,
    sitemap: { changefreq: "daily", priority: "0.8" },
  },
  {
    path: "/home/gallery",
    title: `${SITE_NAME} Gallery`,
    description:
      "Browse visual canvas posts in Iskryb Gallery with community doodles, stamps, and remixes.",
    canonicalPath: "/home/gallery",
    robots: "index,follow",
    prerender: true,
    sitemap: { changefreq: "daily", priority: "0.8" },
  },
  {
    path: "/home/freedom-wall",
    title: `${SITE_NAME} Freedom Wall`,
    description:
      "Join the live weekly Freedom Wall to doodle, drop stickers and stamps, and leave colorful notes with the community.",
    canonicalPath: "/home/freedom-wall",
    robots: "index,follow",
    prerender: true,
    sitemap: { changefreq: "daily", priority: "0.8" },
  },
  {
    path: "/login",
    title: `Log In | ${SITE_NAME}`,
    description: `Log in to ${SITE_NAME} to continue writing and engaging with the community.`,
    canonicalPath: "/login",
    robots: "noindex,follow",
    prerender: true,
  },
  {
    path: "/signUp",
    title: `Sign Up | ${SITE_NAME}`,
    description:
      "Create an Iskryb account to publish journals, share opinions, and curate collections.",
    canonicalPath: "/signUp",
    robots: "noindex,follow",
    prerender: true,
  },
];

const DYNAMIC_PATTERNS = [
  {
    test: (pathname) => /^\/home\/post\/[^/]+(?:\/[^/]+)?$/.test(pathname),
    seo: {
      title: `${SITE_NAME} Post`,
      description: "Read community journals and discussions on Iskryb.",
      canonicalPath: null,
      robots: "index,follow",
    },
  },
];

export const buildAbsoluteUrl = (pathOrUrl = "/") => {
  if (!pathOrUrl) {
    return `${SITE_URL}/`;
  }

  if (/^https?:\/\//i.test(pathOrUrl)) {
    return pathOrUrl;
  }

  return new URL(pathOrUrl, `${SITE_URL}/`).toString();
};

export const getSeoForPath = (pathname) => {
  const normalized = pathname || "/";
  const exactMatch = SEO_ROUTES.find((route) => route.path === normalized);
  if (exactMatch) {
    return { ...DEFAULT_SEO, ...exactMatch };
  }

  const dynamicMatch = DYNAMIC_PATTERNS.find((entry) => entry.test(normalized));
  if (dynamicMatch) {
    return { ...DEFAULT_SEO, ...dynamicMatch.seo };
  }

  return { ...DEFAULT_SEO };
};

export const getPrerenderRoutes = () =>
  SEO_ROUTES.filter((route) => route.prerender).map((route) => route.path);

export const getSitemapRoutes = () =>
  SEO_ROUTES.filter((route) => route.sitemap).map((route) => ({
    path: route.path,
    ...route.sitemap,
  }));

export const buildWebsiteSchema = (canonicalUrl) => ({
  "@context": "https://schema.org",
  "@type": "WebSite",
  name: SITE_NAME,
  url: canonicalUrl,
});

export const ORGANIZATION_SCHEMA = {
  "@context": "https://schema.org",
  "@type": "Organization",
  name: SITE_NAME,
  url: `${SITE_URL}/`,
  logo: DEFAULT_OG_IMAGE,
};

