</body>
</html>`;

        res.set('Content-Type', 'text/html; charset=utf-8');
        return res.send(html);
    } catch (err) {
        console.error('share route error:', err?.message || err);
        return res.redirect(302, buildRedirectUrl(''));
    }
});

