import { lazy, Suspense } from 'react'
import './App.css'
import { Routes, Route, BrowserRouter, Navigate} from 'react-router-dom'
import { useAuth } from './Context/useAuth.js';
import { LexicalComposer } from '@lexical/react/LexicalComposer';
