                                    <span className={`badge-pill ${userData.badge === 'legend' ? 'badge-pill-legend' : 'badge-pill-og'}`}>
                                        {userData.badge === 'legend' ? 'Legend' : 'OG'}
                                    </span>
                                )}
                            </div>
                        </div>

