                                            </div>
                                        </Fragment>
                                    );
                                }

                                if(section.id === 'bio'){
                                    return (
                                        <Fragment key={section.id}>
                                            <div className={`visited-profile-bio-container profile-section-size-${sectionSize}`}>
                                                <p style={{margin: 0, padding: 0}}>{userData?.bio}</p>
                                            </div>
                                        </Fragment>
                                    );
                                }

