            {showSidebar && (
                <MobileSidebarLink onclose={closeSidebar}/>
            )}

            {<MobileNavlink clickOpenSidebar={openSidebar}/>}
            <WriteJournalButton onOpen={handleClickRichtextEditor}/>
        </div>
        </>

