 275→    }
 276→
 277→    const normalizedSort = typeof sort === 'string' && sort.trim().toLowerCase() === 'newest'
 278→        ? 'newest'
 279→        : 'hottest';
 280→
 281→    let url = `${BASE_URL}/journals/canvas/gallery?limit=${parsedLimit}&sort=${encodeURIComponent(normalizedSort)}`;
 282→    if(userId){
 283→        url += `&userId=${encodeURIComponent(userId)}`;
 284→    }
 285→    if(cursor){
 286→        url += `&cursor=${encodeURIComponent(cursor)}`;
 287→    }
 288→
 289→    const response = await apiRequest(url, {
 290→        method: 'GET'
 291→    });
 292→
 293→    if(!response.ok){
 294→        const error = await response.json().catch(() => ({}));
